const curseSurchargeFor = (items: Item[]): number =>
  items.reduce(
    (total, item) =>
      item.cursed ? total + ITEM_CATALOG[item.type].basePremium * 0.5 : total,
    0,
  );

export const runScenario = (input: unknown): unknown => {
  const items = (input as Scenario).steps[0].items;
  const policyBase = policyBaseFor(items);
  const curseSurcharge = curseSurchargeFor(items);
  const premium =
    Math.ceil((policyBase * FIRST_INSURANCE_PERCENT) / 100) + curseSurcharge + PROCESSING_FEE;
  return { results: [{ premium }] };
};
